      const winner = game.getWinner();
      entries.unshift({
        mode: game.getModeLabel(),
        winner: game.players[winner - 1]?.name || 'Player',
        score: game.getPlayerDisplay(winner - 1),
        date: new Date().toISOString().split('T')[0],
